class Solution {
    public int distinctSequences(int n) {
        final int MOD = (int) (1e9 + 7);
        int[][][] dp = new int[n + 1][7][7];
        dp[0][6][6] = 1;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j <= 6; j++) {
                for (int k = 0; k <= 6; k++) {
                    if (dp[i][j][k] == 0) continue;
                    for (int curr = 1; curr <= 6; curr++) {
                        if (gcd(curr, j) != 1) continue;
                        if (k == curr) continue;
                        dp[i + 1][curr][j] = (dp[i + 1][curr][j] + dp[i][j][k]) % MOD;
                    }
                }
            }
        }
        int ans = 0;
        for (int j = 0; j <= 6; j++) {
            for (int k = 0; k <= 6; k++) {
                ans = (ans + dp[n][j][k]) % MOD;
            }
        }
        return ans;
    }

    private int gcd(int a, int b) {
        return b == 0 ? a : gcd(b, a % b);
    }
}
